use std::path::Path;
use std::fs;

pub struct TechStackDetector;

impl TechStackDetector {
    /// 从项目配置文件自动检测技术栈
    pub fn detect_from_project(project_path: &str) -> Vec<String> {
        let mut tech_stack = Vec::new();
        let path = Path::new(project_path);

        // 检测 Rust 项目
        if path.join("Cargo.toml").exists() {
            tech_stack.push("Rust".to_string());
            if let Ok(content) = fs::read_to_string(path.join("Cargo.toml")) {
                if content.contains("\"tauri\"") {
                    tech_stack.push("Tauri".to_string());
                }
                // 检测常见依赖
                if content.contains("\"tokio\"") {
                    tech_stack.push("Tokio".to_string());
                }
                if content.contains("\"serde\"") {
                    tech_stack.push("Serde".to_string());
                }
            }
        }

        // 检测 Node.js 项目
        if path.join("package.json").exists() {
            if let Ok(content) = fs::read_to_string(path.join("package.json")) {
                tech_stack.push("Node.js".to_string());
                if content.contains("\"react\"") {
                    tech_stack.push("React".to_string());
                }
                if content.contains("\"vue\"") {
                    tech_stack.push("Vue".to_string());
                }
                if content.contains("\"typescript\"") {
                    tech_stack.push("TypeScript".to_string());
                }
                if content.contains("\"vite\"") {
                    tech_stack.push("Vite".to_string());
                }
                if content.contains("\"next\"") {
                    tech_stack.push("Next.js".to_string());
                }
            }
        }

        // 检测 Python 项目
        if path.join("requirements.txt").exists() || path.join("pyproject.toml").exists() {
            tech_stack.push("Python".to_string());
            if let Ok(content) = fs::read_to_string(path.join("requirements.txt")) {
                if content.contains("django") {
                    tech_stack.push("Django".to_string());
                }
                if content.contains("fastapi") {
                    tech_stack.push("FastAPI".to_string());
                }
                if content.contains("flask") {
                    tech_stack.push("Flask".to_string());
                }
            }
        }

        tech_stack
    }
}

