use crate::llm::manager::LLMClientManager;
use crate::database::repository::PromptVersionRepository;
use crate::database::models::Message;
use anyhow::Result;

pub struct OpeningIntentAnalyzer {
    llm_manager: LLMClientManager,
    prompt_repo: PromptVersionRepository,
}

impl OpeningIntentAnalyzer {
    pub fn new(llm_manager: LLMClientManager) -> Result<Self> {
        let db_path = crate::database::get_db_path()?;
        Ok(Self {
            llm_manager,
            prompt_repo: PromptVersionRepository::new(db_path),
        })
    }

    /// 分析开场白意图
    pub async fn analyze_opening(
        &self,
        opening_message: &str,
        language: &str,
    ) -> Result<OpeningIntent> {
        // 加载提示词模板
        let template = self.prompt_repo.get_template_by_scenario("opening_intent_analysis")
            .map_err(|e| anyhow::anyhow!("加载提示词模板失败: {}", e))?;

        let template_id = template.id.ok_or_else(|| anyhow::anyhow!("模板 ID 为空"))?;
        let active_version = self.prompt_repo.get_active_version(template_id)
            .map_err(|e| anyhow::anyhow!("获取激活版本失败: {}", e))?;

        let system_prompt = active_version.content;

        // 构建用户消息
        let user_message = format!(
            "请分析以下开场白：\n\n{}",
            opening_message
        );

        // 调用 LLM API
        let response = self.llm_manager.chat_completion(
            vec![
                Message {
                    msg_type: "system".to_string(),
                    content: Some(system_prompt),
                    uuid: String::new(),
                    ..Default::default()
                },
                Message {
                    msg_type: "user".to_string(),
                    content: Some(user_message),
                    uuid: String::new(),
                    ..Default::default()
                },
            ],
            Default::default(),
        ).await
        .map_err(|e| anyhow::anyhow!("LLM API 调用失败: {}", e))?;

        // 解析 JSON 结果
        self.parse_intent_response(&response.content.unwrap_or_default())
    }

    fn parse_intent_response(&self, json_str: &str) -> Result<OpeningIntent> {
        // 尝试提取 JSON（处理可能的前后文本）
        let json_str = self.extract_json(json_str)?;

        let intent: OpeningIntent = serde_json::from_str(json_str)
            .map_err(|e| anyhow::anyhow!("解析 JSON 失败: {}", e))?;

        Ok(intent)
    }

    fn extract_json(&self, text: &str) -> Result<&str> {
        // 查找第一个 { 和最后一个 }
        let start = text.find('{')
            .ok_or_else(|| anyhow::anyhow!("未找到 JSON 开始标记"))?;
        let end = text.rfind('}')
            .ok_or_else(|| anyhow::anyhow!("未找到 JSON 结束标记"))?;

        Ok(&text[start..=end])
    }
}

#[tauri::command]
pub async fn cmd_analyze_opening_intent(
    session_file_path: String,
    manager: State<'_, LLMClientManager>,
) -> Result<OpeningIntent, CommandError> {
    // 1. 读取会话文件
    let messages = crate::session_parser::parse_session_file(&session_file_path)
        .map_err(|e| CommandError::new(&format!("解析会话文件失败: {}", e)))?;

    // 2. 提取第一个用户消息（开场白）
    let opening_message = messages.iter()
        .find(|m| m.msg_type == "user")
        .and_then(|m| m.content.as_ref())
        .ok_or_else(|| CommandError::new("未找到开场白"))?;

    // 3. 检测语言
    let detector = LanguageDetector::new()
        .map_err(|e| CommandError::new(&format!("创建语言检测器失败: {}", e)))?;
    let language = detector.detect_language(opening_message);

    // 4. 调用 IntentAnalyzer
    let analyzer = OpeningIntentAnalyzer::new(manager.inner().clone())
        .map_err(|e| CommandError::new(&format!("创建分析器失败: {}", e)))?;

    let intent = analyzer.analyze_opening(opening_message, &language).await
        .map_err(|e| CommandError::new(&format!("分析失败: {}", e)))?;

    // 5. 保存到数据库（后续任务实现）
    // ...

    Ok(intent)
}

