use regex::Regex;
use anyhow::Result;
use crate::intent_analyzer::qa_detector::DecisionQAPair;

pub struct DecisionDetector {
    decision_keywords: Vec<String>,
    rationale_regex: Regex,
}

impl DecisionDetector {
    pub fn new() -> Result<Self> {
        Ok(Self {
            decision_keywords: vec![
                "选择".to_string(),
                "决定".to_string(),
                "采用".to_string(),
                "使用".to_string(),
                "choose".to_string(),
                "decide".to_string(),
                "adopt".to_string(),
                "use".to_string(),
            ],
            rationale_regex: Regex::new(r"(因为|由于|理由是|reason:?)")?,
        })
    }

    /// 基于规则引擎检测决策点
    pub fn detect_decisions(&self, qa_pair: &DecisionQAPair) -> Vec<DecisionPoint> {
        let mut decisions = Vec::new();

        let combined_text = format!(
            "{} {}",
            qa_pair.user_decision,
            qa_pair.assistant_answer
        );

        // 检查是否包含决策关键词
        for keyword in &self.decision_keywords {
            if combined_text.contains(keyword) {
                let decision = self.extract_decision(&combined_text, keyword);
                decisions.push(decision);
                break; // 每个 QA 对只提取一个主要决策
            }
        }

        decisions
    }

    fn extract_decision(&self, text: &str, keyword: &str) -> DecisionPoint {
        // 提取决策内容
        let decision_made = if let Some(pos) = text.find(keyword) {
            let after_keyword = &text[pos..];
            if let Some(end) = after_keyword.find(|c: char| c == '。' || c == '.' || c == '\n') {
                after_keyword[..end].to_string()
            } else {
                after_keyword.to_string()
            }
        } else {
            String::new()
        };

        // 提取决策依据
        let rationale = if let Some(captures) = self.rationale_regex.captures(text) {
            vec![captures.get(0).map(|m| m.as_str().to_string()).unwrap_or_default()]
        } else {
            Vec::new()
        };

        DecisionPoint {
            decision_type: self.classify_decision_type(text),
            decision_made,
            rationale,
            alternatives: Vec::new(),
            confidence: 0.5, // 规则引擎默认置信度
        }
    }

    fn classify_decision_type(&self, text: &str) -> String {
        if text.contains("架构") || text.contains("architecture") {
            "architecture_design".to_string()
        } else if text.contains("库") || text.contains("library") {
            "technology_choice".to_string()
        } else {
            "implementation".to_string()
        }
    }
}

#[tauri::command]
pub async fn cmd_detect_decisions(
    qa_pair: DecisionQAPair,
) -> Result<Vec<DecisionPoint>, CommandError> {
    let detector = DecisionDetector::new()
        .map_err(|e| CommandError::new(&format!("创建检测器失败: {}", e)))?;

    let decisions = detector.detect_decisions(&qa_pair);

    Ok(decisions)
}
